      "text": "width: 500px;"
    },
    {
      "text": "width: max(50%, 200px);"
    },
    {
      "text": "अमान्य सिंटैक्स"
    }
  ],
  "questionProse": [
    "अगर पैरेंट/कंटेनर की चौड़ाई 400px है, तो नीचे दिए गए एलिमेंट की कम्प्यूटेड चौड़ाई क्या होगी?"
  ],
  "explanationProse": [
    "`min()` फ़ंक्शन `250px` और इसके पैरेंट की चौड़ाई के `50%` में से सबसे छोटा मान चुनेगा।\n\nकम्प्यूटेड वैल्यू समझने के लिए, हमें रिलेटिव यूनिट्स को पिक्सेल में बदलना होगा:\n\n- `400px` का `50%` यानी `200px`\n- `250px` पहले से ही पिक्सेल में है",
    "`min()` फ़ंक्शन रेस्पॉन्सिव डिज़ाइन के लिए खासतौर पर उपयोगी है, जहाँ आप यह सुनिश्चित कर सकते हैं कि कोई कंपोनेंट (या फ़ॉन्ट साइज़) किसी निर्धारित सीमा से आगे न बढ़े।"
  ]
}
